import{r as e}from"./rolldown-runtime-QTnfLwEv.js";import{n as t,t as n}from"./vendor-react-CIxEorsV.js";import{n as r}from"./vendor-router-XxCI5KMz.js";import"./useMeta-Ci6jPQUv.js";import{t as i}from"./SeoPage.module-DkyBZNHX.js";var a=e(t(),1),o=n();function s(){return(0,a.useEffect)(()=>{document.title=`How to Rate Soccer Players | Veyro`;let e={"@context":`https://schema.org`,"@type":`Article`,headline:`How to Rate Soccer Players After Every Match`,description:`A complete guide to rating soccer players using stats, position, and match context. Covers all positions from goalkeeper to attacker.`,author:{"@type":`Organization`,name:`Veyro`},publisher:{"@type":`Organization`,name:`Veyro`,url:`https://darksalmon-lark-983637.hostingersite.com`},datePublished:`2026-06-01`,dateModified:`2026-06-01`,mainEntityOfPage:{"@type":`WebPage`,"@id":`https://darksalmon-lark-983637.hostingersite.com/how-to-rate-soccer-players`}},t=document.createElement(`script`);return t.type=`application/ld+json`,t.text=JSON.stringify(e),document.head.appendChild(t),()=>document.head.removeChild(t)},[]),(0,o.jsx)(`main`,{className:i.seoPage,children:(0,o.jsxs)(`article`,{children:[(0,o.jsxs)(`section`,{className:i.hero,children:[(0,o.jsx)(`div`,{className:i.eyebrow,children:`Rating Guide`}),(0,o.jsx)(`h1`,{className:i.h1,children:`How to rate soccer players after every match.`}),(0,o.jsx)(`p`,{children:`Rating a soccer player after a match is harder than it looks. Goals and assists tell part of the story. But a central midfielder who wins twelve duels, completes forty-three passes, and prevents two dangerous attacks may deserve a higher rating than a striker who scored once and went missing for seventy minutes. This guide explains how to build a fair, consistent rating system for any position.`}),(0,o.jsxs)(`div`,{className:i.actions,children:[(0,o.jsx)(r,{className:i.button,to:`/`,children:`Try the Free Calculator`}),(0,o.jsx)(r,{className:i.button,to:`/soccer-performance-guide`,children:`Full Performance Guide`})]})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`Why a rating system matters.`}),(0,o.jsx)(`p`,{children:`Without a system, player ratings are just opinions. Two coaches watching the same match often land on completely different assessments because they are watching different things. A structured rating system creates a shared language between coaches, players, and parents. It shifts conversations from "you played badly" to "your duels won dropped from eight to three — here is why that matters."`}),(0,o.jsx)(`p`,{children:`A good rating system does three things: it rewards what each position is actually responsible for, it accounts for match context so a player is never judged unfairly for a tough opponent or a short substitution, and it produces a number that is consistent enough to track over time.`})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`The core inputs for any rating.`}),(0,o.jsxs)(`div`,{className:i.grid,children:[(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Position`}),(0,o.jsx)(`span`,{children:`A goalkeeper's rating should weight saves and clean sheets heavily. A striker's rating should weight goals and key passes. The formula changes completely by position.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Minutes played`}),(0,o.jsx)(`span`,{children:`A player who comes on for fifteen minutes cannot be compared directly to a player who plays ninety. Scale all volume stats by minutes to get a fair comparison.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Match context`}),(0,o.jsx)(`span`,{children:`Opponent strength, weather, pitch condition, and whether the team won or lost all affect how individual stats should be read.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Positive actions`}),(0,o.jsx)(`span`,{children:`Goals, assists, key passes, duels won, successful dribbles, shots on target, saves, clean sheets, and passes completed all contribute positively.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Negative actions`}),(0,o.jsx)(`span`,{children:`Turnovers, fouls, yellow cards, red cards, shots missed, goals conceded, and costly errors reduce the rating.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Decisive moments`}),(0,o.jsx)(`span`,{children:`A goal that wins the match, a penalty saved, or a last-minute tackle should carry more weight than the same action in a comfortable win.`})]})]})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`How to rate a goalkeeper.`}),(0,o.jsx)(`p`,{children:`Goalkeepers are the hardest position to rate fairly because their impact is often invisible. A goalkeeper who makes zero saves in a 3-0 win may have played perfectly, distributing well, commanding their area, and organizing the defense. A goalkeeper who makes eight saves in a 1-0 loss may have been the reason the team was still in the match.`}),(0,o.jsx)(`p`,{children:`The most important stats for a goalkeeper rating are saves made, goals conceded, clean sheet (yes or no), high balls claimed, distribution accuracy, and whether any goals conceded were the result of a goalkeeper error. A base score for a goalkeeper starts at around 62 out of 100, adjusting upward for saves and clean sheets and downward for goals conceded and errors.`})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`How to rate a defender.`}),(0,o.jsx)(`p`,{children:`Defenders are judged on whether the team kept a clean sheet, how many duels they won, how few dangerous mistakes they made, and how well they distributed the ball under pressure. A center-back who wins seven of eight aerial duels, makes two key blocks, and completes eighty percent of their passes is having an excellent match even if the scoreline does not show it.`}),(0,o.jsx)(`p`,{children:`Defensive rating inputs: duels won, possession won, clearances, blocks, interceptions, fouls committed, yellow or red cards, and turnovers in dangerous areas. A base score of 64 is reasonable for a defender, moving upward for clean sheets and high duel win rates, downward for fouls and costly errors.`})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`How to rate a midfielder.`}),(0,o.jsx)(`p`,{children:`Midfielders are the engine of the team and the hardest to rate with simple stats. The best midfielders do things that do not appear in a basic stats sheet: they press intelligently, they recycle possession under pressure, they cover space that no one notices until it goes wrong. For rating purposes, focus on passes completed, duels won, possession won, shots, key passes, assists, and turnovers.`}),(0,o.jsx)(`p`,{children:`A central midfielder base score starts around 66. A box-to-box midfielder who completes forty-five passes, wins six duels, and contributes one key pass is having a strong match. An attacking midfielder is weighted more toward chances created and goals, while a defensive midfielder is weighted more toward possession won and duels.`})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`How to rate an attacker.`}),(0,o.jsx)(`p`,{children:`Attackers are the most straightforward position to rate because goals and assists are visible and unambiguous. But an attacker who plays well without scoring — pressing defenders into mistakes, creating three chances that teammates miss — deserves credit for that work too. The best attacker ratings combine goals, assists, shots on target, key passes, successful dribbles, and the attacker's overall involvement in dangerous play.`}),(0,o.jsx)(`p`,{children:`A base score of 65 for attackers moves sharply upward for goals (especially decisive ones) and downward for a long run of shots missed or no involvement in attacking play.`})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`A simple rating scale to use.`}),(0,o.jsxs)(`div`,{className:i.grid,children:[(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`90–100`}),(0,o.jsx)(`span`,{children:`Exceptional. Match-winning performance. Top-of-position stats with no costly errors.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`80–89`}),(0,o.jsx)(`span`,{children:`Very good. Clearly above average for the position. Strong contribution in most key areas.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`70–79`}),(0,o.jsx)(`span`,{children:`Good. Solid performance with some standout moments. A reliable showing.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`60–69`}),(0,o.jsx)(`span`,{children:`Average. Did the basics but limited impact. Expected level for the game.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`50–59`}),(0,o.jsx)(`span`,{children:`Below average. Struggled in key areas. Stats were below position expectations.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Below 50`}),(0,o.jsx)(`span`,{children:`Poor. Costly errors, very low contribution, or early red card.`})]})]})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`How Veyro calculates ratings automatically.`}),(0,o.jsxs)(`p`,{children:[`The `,(0,o.jsx)(r,{to:`/`,children:`Veyro soccer rating calculator`}),` uses a position-based formula that weights each stat by its importance for that position. You enter the player's position, minutes played, and the key stats for the match. The calculator handles the math and returns a rating out of 100. You can then save the result to the `,(0,o.jsx)(r,{to:`/vault`,children:`match vault`}),` to track performance over time.`]}),(0,o.jsx)(`p`,{children:`The formula starts with a position-specific base score, adds scaled positive contributions (weighted by minutes played), and subtracts for turnovers, fouls, and decisive errors. The result is clamped between 1 and 100 so no single match can produce an impossible score.`})]}),(0,o.jsxs)(`section`,{className:i.section,children:[(0,o.jsx)(`h2`,{children:`FAQ.`}),(0,o.jsxs)(`div`,{className:i.grid,children:[(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Can I rate any position?`}),(0,o.jsx)(`span`,{children:`Yes. Veyro supports goalkeeper, defender, midfielder, and attacker ratings, each with a different formula that weights the stats that matter most for that role.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Should I rate players after every game?`}),(0,o.jsx)(`span`,{children:`Yes. One game gives a snapshot, but five or more games reveal patterns. A single high or low rating can be misleading without context.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`How do I handle a player who played two positions?`}),(0,o.jsx)(`span`,{children:`Rate using the position the player spent the most minutes in. Note the position change in the match notes.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`What if I don't have all the stats?`}),(0,o.jsx)(`span`,{children:`Use the stats you have. A rating based on partial stats is still more useful than no rating at all. Focus on the most important stats for the position.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`Is a higher rating always better?`}),(0,o.jsx)(`span`,{children:`In context, yes. But a 74 from a goalkeeper under heavy pressure against a strong team may be more impressive than an 82 from an attacker who scored one tap-in against weak opposition.`})]}),(0,o.jsxs)(`div`,{className:i.card,children:[(0,o.jsx)(`strong`,{children:`How do youth players benefit from ratings?`}),(0,o.jsx)(`span`,{children:`Ratings give youth players a concrete number to work toward, a way to track improvement, and a starting point for self-reflection without relying only on coach feedback.`})]})]})]})]})})}export{s as default};